    @rpc(Unicode, Unicode, Integer, Unicode, _returns=TransferResponse, _operation_name='transferFunds')
    def transfer_funds(ctx, from_account, to_account, amount, description=None):
        """
        Transfer funds between two accounts
        """
        logger.info(f"transferFunds called: {from_account} -> {to_account}, amount: {amount}")
        
        if not from_account or not to_account:
            raise Fault(faultcode="Client", faultstring="Both from_account and to_account are required")
        
        if amount <= 0:
            raise Fault(faultcode="Client", faultstring="Transfer amount must be greater than zero")
        
        if from_account not in accounts_db:
            raise Fault(faultcode="Client", faultstring=f"Source account {from_account} not found")
        
        if to_account not in accounts_db:
            raise Fault(faultcode="Client", faultstring=f"Destination account {to_account} not found")
        
        if from_account == to_account:
            raise Fault(faultcode="Client", faultstring="Cannot transfer to the same account")
        
        from_acc = accounts_db[from_account]
        to_acc = accounts_db[to_account]
        
        if from_acc["balance"] < amount:
            raise Fault(faultcode="Client", faultstring="Insufficient funds")
        
        if from_acc["status"] != "Active" or to_acc["status"] != "Active":
            raise Fault(faultcode="Client", faultstring="One or both accounts are not active")
        
        # Perform transfer
        accounts_db[from_account]["balance"] -= amount
        accounts_db[to_account]["balance"] += amount
        
        # Generate transaction ID
        transaction_id = f"TXN{datetime.now().strftime('%Y%m%d%H%M%S')}{len(transactions_log)+1}"
        timestamp = datetime.now().isoformat()
        
        # Log transaction
        transaction = {
            "transaction_id": transaction_id,
            "from_account": from_account,
            "to_account": to_account,
            "amount": amount,
            "description": description or "Fund transfer",
            "timestamp": timestamp,
            "status": "Completed"
        }
        transactions_log.append(transaction)
        
        response = TransferResponse()
        response.transaction_id = transaction_id
        response.status = "Success"
        response.message = f"Successfully transferred {amount} from {from_account} to {to_account}"
        response.timestamp = timestamp
        
        logger.info(f"Transfer completed: {transaction_id}")
        return response
    
